queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?course_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasCourses ?child ; p:hasJournalism_Schools ?parent . } GROUP BY ?child }
  ?child p:course_name ?course_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Journalism_Schools } }
  FILTER(?nf = ?total)
}

